class MyCalendarThree:

    def __init__(self):
        self.events = {}

    def book(self, startTime: int, endTime: int) -> int:
        self.events[startTime] = self.events.get(startTime, 0) + 1
        self.events[endTime] = self.events.get(endTime, 0) - 1
        max_bookings = active_bookings = 0
        for time in sorted(self.events):
            active_bookings += self.events[time]
            max_bookings = max(max_bookings, active_bookings)
        return max_bookings


